import {
  Component,
  Prop,
  Element,
  h,
  Host,
  State,
  Watch,
  Event,
  EventEmitter
} from '@stencil/core';


interface KdsImageHostElement extends HTMLElement {
  nativeElement: HTMLElement;
}

@Component({
  tag: 'kds-image',
  styleUrl: 'kds-image.css',
  shadow: false
})
export class KdsImage {
  @Element() hostEl: KdsImageHostElement;

  /** Defines alternative text of an image. */
  @Prop() readonly alt: string;
  /** Defines the image source. */
  @Prop() readonly src: string;
  /** Defines custom icon when image src not provided. */
  @Prop() readonly icon?: string;
  /** Sets a variety of image sources. */
  @Prop() readonly srcset?: string;
  /** Defines a set of source sizes. */
  @Prop() readonly sizes?: string;
  /** Gives authors control over when the browser should start loading the image. */
  @Prop() readonly loading?: 'lazy' | 'eager' | 'auto' = 'eager';
  /** Sets how the image should be resized to fit its wrapping container. */
  @Prop() readonly objectFit?: 'fill' | 'contain' | 'cover' | 'none' | 'scale-down';
  /**  Specifies the alignment of the image within the wrapping container. */
  @Prop() readonly objectPosition?: string;

  @State() isLoading: boolean = true;
  @State() isError: boolean = false;

  /** Emits image's native load event. */
  @Event() imageLoad: EventEmitter<any>;
  /** Emits image's native error event. */
  @Event() imageError: EventEmitter<any>;

  private handleImageError = (event: Event) => {
    this.isLoading = false;
    this.isError = true;
    this.imageError.emit(event);
  };

  private handleImageLoad = (event: Event) => {
    this.isLoading = false;
    this.imageLoad.emit(event);
  };

  @Watch('src')
  resetState() {
    this.isError = false;
    this.isLoading = true;
  }

  render() {
    const {
      src,
      alt,
      icon,
      srcset,
      sizes,
      loading,
      isLoading,
      isError,
      objectFit,
      objectPosition,
      handleImageError,
      handleImageLoad
    } = this;

    const Icon = icon;

    const image = (
      <img
        src={src}
        alt={alt}
        class='kds-Image-img'
        height={isLoading ? 11 : undefined}
        width={isLoading ? 0 : undefined}
        srcset={srcset}
        sizes={sizes}
        loading={loading}
        onError={handleImageError}
        onLoad={handleImageLoad}
        style={{
          'object-fit': objectFit,
          'object-position': objectPosition
        }}
      />
    );
    /*
    Setting height and width based on loading state taken from kds-react. The justificaiton:
    We can't use hidden={isLoading} because Chrome's native lazy-loading won't work on
    most hidden images. display:none doesn't work either. See here:
    https://bugs.chromium.org/p/chromium/issues/detail?id=1016689
    And for why I'm specifically choosing height 11 and width 0 as a workaround, see here:
    https://bugs.chromium.org/p/chromium/issues/detail?id=1025746
    (width in particular is 0 because height gets overridden by CSS)
    */

    /** For images without defined `src` prop:
     * If no `icon` prop is defined, the default is either `kds-icon-camera` or `kds-icon-groceries`.
     * `kds-icon-camera` will appear if theme on application is set to "admin".
     * */
    const noSrc = icon ? (
      Icon && <Icon size='xl' color='subdued' />
    ) : document.documentElement.getAttribute('kds-theme') === 'admin' ? (
      <kds-icon-camera size='xl' color='subdued' />
    ) : (
      <kds-icon-groceries size='xl' color='subdued' />
    );

    /** If an image has a defined src prop but it errors out, a broken image SVG will be returned.
     * If no src has been defined, an icon defined by noSrc will be used. */
    const error = (
      <div class='kds-Image-error' hidden={isLoading}>
        {src ? <kds-icon-image-missing size='xl' color='subdued' /> : noSrc}
      </div>
    );

    const skeleton = <div class='kds-Image-skeleton' />;

    return (
      <Host class='kds-Image' aria-busy={!!isLoading}>
        {isError ? error : image}
        {isLoading && skeleton}
      </Host>
    );
  }
}
